import React, { useCallback, useMemo, useState } from 'react';
import {
  Button,
  Select,
  dispatchAppToast,
  loadErpListTableConfig,
  saveErpListTableConfig,
  LinListTableConfigModal,
  LinPageLayout,
  useCatalogTableBusy,
  type ErpListTableConfig,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { PayslipDto } from '../../../services/ns/models';
import { bhxhReportPageLabels as labels } from '../../../constants/bhxhReportPageLabels';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/periodFilter';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useHrPayrollPermissions } from '../../../hooks/useHrPermissions';
import { formatVnd } from '../../../utils/format';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-bhxh';
const PAGE_ID = 'ns-bhxh';

const BhxhReportPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { canRead } = useHrPayrollPermissions();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [rows, setRows] = useState<PayslipDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [configOpen, setConfigOpen] = useState(false);
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(`${TEST_ID}-report-table-config`),
  );

  const { showTableLoading } = useCatalogTableBusy(loading);
  const yearSelectOptions = useMemo(() => yearOptions(), []);

  const handleLoad = useCallback(() => {
    setLoading(true);
    hrService
      .getPayslips({ month, year, pageSize: 500 })
      .then(res => {
        setRows(res.items);
        setLoaded(true);
      })
      .catch(err => {
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, labels.loadError),
          type: 'error',
        });
      })
      .finally(() => setLoading(false));
  }, [dispatch, month, year]);

  const handleExport = useCallback(() => {
    const qs = new URLSearchParams({ month: String(month), year: String(year) });
    const a = document.createElement('a');
    a.href = `${import.meta.env.VITE_API_URL}/hr/payslips/bhxh-report/export-excel?${qs}`;
    a.download = `BHXH-T${month}-${year}.xlsx`;
    a.click();
  }, [month, year]);

  const handleSaveTableConfig = (next: ErpListTableConfig) => {
    setTableConfig(next);
    saveErpListTableConfig(`${TEST_ID}-report-table-config`, next);
  };

  const hasData = rows.length > 0;

  const headerHint = useMemo(
    () =>
      loaded && hasData
        ? `T${month}/${year} · ${rows.length} ${labels.summaryCount}`
        : undefined,
    [loaded, hasData, month, year, rows.length],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-month`,
        content: (
          <Select
            label={labels.monthLabel}
            value={String(month)}
            onChange={e => setMonth(Number(e.target.value))}
            options={MONTH_OPTIONS}
            fullWidth
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-year`,
        content: (
          <Select
            label={labels.yearLabel}
            value={String(year)}
            onChange={e => setYear(Number(e.target.value))}
            options={yearSelectOptions}
            fullWidth
          />
        ),
      },
      {
        testId: `${TEST_ID}-view-btn`,
        content: (
          <Button
            variant="primary"
            onClick={handleLoad}
            loading={loading}
            data-testid={`${TEST_ID}-view-btn`}
          >
            {labels.view}
          </Button>
        ),
      },
      ...(canRead
        ? [
            {
              testId: `${TEST_ID}-export-btn`,
              content: (
                <Button
                  variant="secondary"
                  onClick={handleExport}
                  disabled={!hasData}
                  data-testid={`${TEST_ID}-export-btn`}
                >
                  <i className="fas fa-file-excel" /> {labels.exportAction}
                </Button>
              ),
            },
          ]
        : []),
    ],
    [month, year, yearSelectOptions, handleLoad, loading, canRead, handleExport, hasData],
  );

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: handleLoad,
      canChart: hasData,
      onChart: () =>
        dispatchAppToast(dispatch, { message: labels.chartComingSoon, type: 'info' }),
      canPrint: hasData,
      onPrint: () => window.print(),
      onEditConfig: () => setConfigOpen(true),
    }),
    [handleLoad, hasData, dispatch],
  );

  const listBody =
    loaded && !showTableLoading && rows.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{labels.empty}</p>
      </div>
    ) : loaded && !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table
          className={erp.table}
          data-testid={`${TEST_ID}-table`}
        >
          <thead>
            <tr>
              <th>{labels.colEmployee}</th>
              <th className={erp.colRight}>{labels.colBaseSalary}</th>
              <th className={erp.colRight}>{labels.colDeductions}</th>
              <th className={erp.colRight}>{labels.colNetSalary}</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((r, i) => (
              <tr key={r.id} data-testid={`${TEST_ID}-row-${i}`}>
                <td>{r.employeeName}</td>
                <td className={erp.colRight}>{formatVnd(r.baseSalary)}</td>
                <td className={erp.colRight}>{formatVnd(r.deductions)}</td>
                <td className={erp.colRight}>{formatVnd(r.netSalary)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-shield-alt',
          pageId: PAGE_ID,
          hint: headerHint,
        }}
        reportToolbar={reportToolbar}
        listTitle={labels.listTitle}
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        modals={(
          <LinListTableConfigModal
            isOpen={configOpen}
            onClose={() => setConfigOpen(false)}
            testIdPrefix={TEST_ID}
            config={tableConfig}
            onSave={handleSaveTableConfig}
          />
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default BhxhReportPage;
